      p_limit: BATCH_SIZE,
      p_offset: currentOffset
    });

    if (fetchErr) {
      console.error(`[AUDITOR][${reqId}][FATAL] Fetching words failed:`, fetchErr);
      throw fetchErr;
    }

    // ==========================================
    // 3. IF NO WORDS LEFT -> RUN DEEP AUDIT
    // ==========================================
    if (!wordList || wordList.length === 0) {
