      // B. Get Recent Failures from DB
      const { data: recentErrors } = await supabase.from('validation_tracking')
        .select('file_path, last_error, status')
        .not('last_error', 'is', null)
        .limit(10);

      // C. Count Pending/Processing/Completed
      const { data: statusCounts } = await supabase.from('validation_tracking').select('status');
      const counts = (statusCounts || []).reduce((acc: any, row: any) => {
        acc[row.status] = (acc[row.status] || 0) + 1;
        return acc;
      }, {});

      const report = {
        message: "SYSTEM_AUDIT_REPORT",
        checkpoint_offset: currentOffset,
        database_tracking_total: totalInDB,
        database_status_breakdown: counts,
        storage_sample_count: storageFiles?.length || 0,
        storage_top_files: storageFiles?.slice(0, 5).map(f => f.name),
        recent_system_errors: recentErrors,
        advice: (storageFiles?.length === 0 && totalInDB > 0) 
          ? "CRITICAL: Database has file paths but Storage is EMPTY. Run TRUNCATE on validation_tracking."
          : "System appears synchronized. If 'Object Not Found' persists, check bucket name case-sensitivity."
      };

      console.log(`[AUDITOR][${reqId}] Audit Complete:`, JSON.stringify(report, null, 2));
      return new Response(JSON.stringify(report), { headers: { 'Content-Type': 'application/json' } });
    }

    // ==========================================
    // 4. PROCESS UPLOADS (If wordList is not empty)
    // ==========================================
    console.log(`[AUDITOR][${reqId}] Processing ${wordList.length} words into ${Math.ceil(wordList.length / WORDS_PER_FILE)} files...`);

    const uploadTasks = [];
    for (let i = 0; i < wordList.length; i += WORDS_PER_FILE) {
      const chunk = wordList.slice(i, i + WORDS_PER_FILE);
      const startIdx = currentOffset + i + 1;
      const endIdx = currentOffset + i + chunk.length;

      const content = chunk.map((w: any, idx: number) => {
        const word = w.extracted_word || 'N/A';
        return `${startIdx + idx}. ${word}`;
      }).join('\n');

      const fileName = `batch_${startIdx}_to_${endIdx}.txt`;

      // Log a sample every 50 files to avoid log flooding
      if (i % 5000 === 0) console.log(`[AUDITOR][${reqId}] Preparing task for: ${fileName}`);

      const task = (async () => {
        const { error: upErr } = await supabase.storage.from('inspection_bucket').upload(fileName, content, { upsert: true });
        if (upErr) console.error(`[AUDITOR][${reqId}][UPLOAD_FAIL] ${fileName}:`, upErr);
        return { fileName, success: !upErr };
      })();

      uploadTasks.push(task);
    }

    console.log(`[AUDITOR][${reqId}] Starting parallel upload groups (Limit: ${CONCURRENCY_LIMIT})...`);

    let successCount = 0;
    for (let i = 0; i < uploadTasks.length; i += CONCURRENCY_LIMIT) {
        const group = uploadTasks.slice(i, i + CONCURRENCY_LIMIT);
        const results = await Promise.all(group);
        successCount += results.filter(r => r.success).length;
        if (i % 100 === 0) console.log(`[AUDITOR][${reqId}][PROGRESS] Finished ${i + group.length} / ${uploadTasks.length} uploads.`);
    }

    // ==========================================
    // 5. UPDATE PROGRESS
    // ==========================================
    const nextOffset = currentOffset + wordList.length;
    console.log(`[AUDITOR][${reqId}] All uploads done. Updating checkpoint to ${nextOffset}...`);
    await supabase.from('export_checkpoint').update({ last_offset: nextOffset }).eq('id', 1);

    const duration = ((Date.now() - startTime) / 1000).toFixed(1);

    return new Response(JSON.stringify({
      status: "SUCCESS",
      execution_time: `${duration}s`,
      words_processed: wordList.length,
      files_created_successfully: successCount,
      total_attempted: uploadTasks.length,
      new_offset: nextOffset
    }));

  } catch (err) {
    console.error(`[AUDITOR][${reqId}][CRITICAL_EXCEPTION]`, err);
    return new Response(JSON.stringify({ error: err.message, stack: err.stack }), { status: 500 });
  }
})

