1765 |     function smartJSONParse(jsonString) {
1766 |         try {
1767 |             return JSON.parse(jsonString);
1768 |         } catch (e) {
1769 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1770 |             let fixed = jsonString
1771 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1772 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1773 |                 // 2. Fix literal newlines inside strings (replace with \n)
1774 |                 .replace(/(\n)/g, (match, p1, offset) => {
1775 |                     // Only replace if we are likely inside a quoted string
1776 |                     const before = jsonString.slice(0, offset);
1777 |                     const quoteCount = (before.match(/"/g) || []).length;
1778 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1779 |                 });
1780 | 
1781 |             try {
1782 |                 const cleanObj = JSON.parse(fixed);
1783 |                 document.getElementById('json-input').value = fixed;
1784 |                 if (typeof saveState === 'function') saveState();
1785 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
