2012 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2013 |     function applyLocalPatch(content, ops) {
2014 |         let lines = content.split('\n');
2015 |         let logs = [];
2016 |         let success = true;
2017 | 
2018 |         if (typeof ops === 'string') {
2019 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2020 |         }
2021 | 
2022 |         ops.forEach(op => {
2023 |             if (op.action === 'comment') return;
2024 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2025 |             
2026 |             if (op.action === 'replace_block') {
2027 |                 // Strategy 1: Exact String Match (Fastest)
2028 |                 const currentStr = lines.join('\n');
2029 |                 if (currentStr.includes(op.find_block)) {
2030 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2031 |                     logs.push('Exact match applied');
2032 |                     return;
2033 |                 }
2034 | 
2035 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2036 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2037 |                 if (searchLines.length === 0) return;
2038 | 
2039 |                 let matchStart = -1;
2040 |                 let matchEnd = -1;
2041 | 
2042 |                 // Scan file lines
2043 |                 for (let i = 0; i < lines.length; i++) {
2044 |                     // If first line matches (ignoring whitespace)
2045 |                     if (lines[i].trim() === searchLines[0]) {
2046 |                         // Check subsequent lines
2047 |                         let allMatch = true;
2048 |                         let fileOffset = 0;
2049 |                         let searchOffset = 1;
2050 |                         
2051 |                         while (searchOffset < searchLines.length) {
2052 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2053 |                             const nextFile = lines[i + fileOffset + 1].trim();
2054 |                             // Skip empty lines in file if they aren't in search block
2055 |                             if (nextFile === '') {
2056 |                                 fileOffset++;
2057 |                                 continue;
2058 |                             }
2059 |                             if (nextFile !== searchLines[searchOffset]) {
2060 |                                 allMatch = false;
2061 |                                 break;
2062 |                             }
2063 |                             fileOffset++;
2064 |                             searchOffset++;
2065 |                         }
2066 | 
2067 |                         if (allMatch) {
2068 |                             matchStart = i;
2069 |                             matchEnd = i + fileOffset;
2070 |                             break;
2071 |                         }
2072 |                     }
2073 |                 }
2074 | 
2075 |                 if (matchStart !== -1) {
2076 |                     // Replace the range of lines
2077 |                     const replacement = op.replace_with.split('\n');
2078 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2079 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2080 |                 } else {
2081 |                     success = false;
2082 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2083 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2084 |                 }
2085 |             }
2086 |         });
2087 |         return { content: lines.join('\n'), success, logs };
2088 |     }
