2092 |     async function runAutoFixLoop(name, code, errorList) {
2093 |         const status = document.getElementById('ef-status-msg');
2094 |         let currentCode = code;
2095 |         let currentErrors = errorList;
2096 | 
2097 |         // Fix one by one (recursive loop)
2098 |         async function fixNext(index) {
2099 |             if (index >= currentErrors.length) return true; // All initial errors processed
2100 | 
2101 |             const err = currentErrors[index];
2102 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2103 |             status.style.color = "#eab308"; // Dev yellow
2104 | 
2105 |             try {
2106 |                 // 1. Get Patch from AI
2107 |                 const res = await fetch(CONFIG.funcUrl, { 
2108 |                     method: 'POST', 
2109 |                     headers: {'Content-Type': 'application/json'},
2110 |                     body: apiBody({ 
2111 |                         action: 'propose_syntax_fix', 
2112 |                         code: currentCode, 
2113 |                         error: err 
2114 |                     })
2115 |                 });
2116 |                 const data = await res.json();
2117 |                 const ops = data.operations;
2118 | 
2119 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2120 | 
2121 |                 // 2. Apply Patch Locally
2122 |                 const patchResult = applyLocalPatch(currentCode, ops);
2123 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2124 | 
2125 |                 currentCode = patchResult.content;
2126 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2127 | 
2128 |                 // 3. Re-Validate
2129 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2130 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2131 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2132 |                 });
2133 |                 const scanData = await scanRes.json();
2134 | 
2135 |                 if (scanData.valid) {
2136 |                     status.innerText = "✅ Syntax Fixed!";
2137 |                     return true;
2138 |                 } else {
2139 |                     // If errors remain, update list and Prompt user
2140 |                     currentErrors = scanData.errors;
2141 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2142 |                         // Recursively fix the *new* first error (since layout changed)
2143 |                         return await fixNext(0);
2144 |                     } else {
2145 |                         return false;
2146 |                     }
2147 |                 }
2148 | 
2149 |             } catch (e) {
2150 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2151 |                     return await fixNext(index);
2152 |                 } else {
2153 |                     return false;
2154 |                 }
2155 |             }
2156 |         }
2157 | 
2158 |         return await fixNext(0);
2159 |     }
