4761 |     function formatBytes(bytes) {
4762 |         if (!bytes) return '0 B';
4763 |         const k = 1024;
4764 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4765 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4766 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4767 |     }
