4769 |     function timeAgo(dateString) {
4770 |         const date = new Date(dateString);
4771 |         const now = new Date();
4772 |         const seconds = Math.floor((now - date) / 1000);
4773 |         if (seconds < 10) return 'just now';
4774 |         if (seconds < 60) return seconds + 's ago';
4775 |         const minutes = Math.floor(seconds / 60);
4776 |         if (minutes < 60) return minutes + 'm ago';
4777 |         const hours = Math.floor(minutes / 60);
4778 |         if (hours < 24) return hours + 'h ago';
4779 |         return date.toLocaleDateString();
4780 |     }
