4979 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
4980 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
4981 |         
4982 |         const navItems = document.querySelectorAll('.nav-item');
4983 |         switchTab(tabId, navItems[navIndex]);
4984 | 
4985 |         const scrollContainer = document.querySelector('.main-view');
4986 |         let retryCount = 0;
4987 |         const MAX_RETRIES = 5;
4988 | 
4989 |         const attemptNavigation = async () => {
4990 |             const element = document.querySelector(selector);
4991 |             
4992 |             if (element) {
4993 |                 console.log("[DeepJump] Element found. Scrolling...");
4994 |                 
4995 |                 // Wait for any tab transition animations
4996 |                 await new Promise(r => setTimeout(r, 300));
4997 | 
4998 |                 let offsetTop = 0;
4999 |                 let curr = element;
5000 |                 while (curr && curr !== scrollContainer) {
5001 |                     offsetTop += curr.offsetTop;
5002 |                     curr = curr.offsetParent;
5003 |                 }
5004 | 
5005 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5006 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5007 | 
5008 |                 // Visual Highlight
5009 |                 element.style.transition = 'all 0.5s ease';
5010 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5011 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5012 |                 setTimeout(() => {
5013 |                     element.style.backgroundColor = '';
5014 |                     element.style.boxShadow = '';
5015 |                 }, 3000);
5016 |                 
5017 |                 console.groupEnd();
5018 |                 return true;
5019 |             }
5020 | 
5021 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5022 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5023 |                 retryCount++;
5024 |                 showGlobalToast("🔍 Searching deeper...");
5025 |                 
5026 |                 await loadMoreFn(); 
5027 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5028 |                 return attemptNavigation();
5029 |             }
5030 | 
5031 |             console.error("[DeepJump] Failed: Element not found after retries.");
5032 |             showGlobalToast("Entry not found in recent history.", true);
5033 |             console.groupEnd();
5034 |             return false;
5035 |         };
5036 | 
5037 |         setTimeout(attemptNavigation, 100);
