7004 |     function extractTableNames(sql) {
7005 |         if (!sql) return [];
7006 |         const tables = [];
7007 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7008 |         
7009 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7010 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7011 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7012 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7013 | 
7014 |         let match;
7015 |         while ((match = fromRegex.exec(sql)) !== null) {
7016 |             const name = match[1];
7017 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7018 |                 tables.push(name);
7019 |             }
7020 |         }
7021 |         
7022 |         while ((match = metaRegex.exec(sql)) !== null) {
7023 |             const name = match[1];
7024 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7025 |                 tables.push(name);
7026 |             }
7027 |         }
7028 | 
7029 |         return tables;
7030 |     }
7031 | 
7032 |     function convertToCSV(resultObj) {
7033 |         const data = resultObj.data || [];
7034 |         if (!data.length) return '';
7035 |         
7036 |         const tables = extractTableNames(resultObj.sql);
7037 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7038 | 
7039 |         const headers = Object.keys(data[0]);
7040 |         const rows = data.map(row => 
7041 |             headers.map(header => {
7042 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7043 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7044 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7045 |             }).join(',')
7046 |         );
7047 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7048 |     }
