import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';

Deno.serve(async (req) => {
  const reqId = Math.random().toString(36).substring(7);
  console.log(`[SYSTEM_INSPECTOR][${reqId}] Audit started...`);

  const supabase = createClient(
    Deno.env.get('SUPABASE_URL') ?? '',
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
  );

  try {
    // 1. Fetch Storage Reality
    // We list up to 10,000 files to ensure we see everything
    const { data: storageFiles, error: listErr } = await supabase.storage
      .from('inspection_bucket')
      .list('', { limit: 10000 });

    if (listErr) throw listErr;

    const actualFiles = (storageFiles || []).filter(f => f.name.endsWith('.txt'));
    const storageFileNames = new Set(actualFiles.map(f => f.name));

    // 2. Calculate Total Words in Storage based on filenames
    let totalWordsInStorage = 0;
    actualFiles.forEach(f => {
      const match = f.name.match(/batch_(\d+)_to_(\d+)/);
      if (match) {
        const start = parseInt(match[1]);
        const end = parseInt(match[2]);
        totalWordsInStorage += (end - start + 1);
      }
    });

    // 3. Fetch Database Reality
    const { data: dbRows, error: dbErr } = await supabase
      .from('validation_tracking')
      .select('file_path, status, last_error');

    if (dbErr) throw dbErr;

    const dbFilePaths = dbRows || [];
    const dbFileCount = dbFilePaths.length;

    // 4. Identify Discrepancies (Ghosts vs Missing)
    const ghosts: string[] = []; // In DB but not in Storage
    const validInDB: string[] = [];

    dbFilePaths.forEach(row => {
      if (!storageFileNames.has(row.file_path)) {
        ghosts.push(row.file_path);
      } else {
        validInDB.push(row.file_path);
      }
    });

    // 5. Check for files in Storage that are NOT in the DB yet
    const missingFromDB = actualFiles
      .map(f => f.name)
      .filter(name => !dbFilePaths.some(row => row.file_path === name));

    // 6. Get Summary Stats
    const stats = dbFilePaths.reduce((acc: any, row: any) => {
      acc[row.status] = (acc[row.status] || 0) + 1;
      return acc;
    }, {});

    const finalReport = {
      timestamp: new Date().toISOString(),
      storage_summary: {
        total_files_in_bucket: actualFiles.length,
        total_estimated_words: totalWordsInStorage,
        bucket_name: "inspection_bucket"
      },
      database_summary: {
        total_rows_in_tracking_table: dbFileCount,
        status_breakdown: stats
      },
      discrepancy_report: {
        ghost_files_count: ghosts.length,
        ghost_files_sample: ghosts.slice(0, 10), 
        missing_from_db_count: missingFromDB.length,
        missing_from_db_sample: missingFromDB.slice(0, 10)
      },
      conclusion: ghosts.length > 0 
        ? `ALERT: You have ${ghosts.length} 'Ghost' entries in your DB that don't exist in Storage. This is causing the 'Object not found' errors.`
        : "Sync looks good. No ghost files detected.",
      recommended_action: ghosts.length > 0
        ? "Run: DELETE FROM validation_tracking WHERE file_path IN ('" + ghosts.slice(0, 5).join("','") + "'...) or simply cleanup the table."
        : "Continue processing."
    };

    console.log(`[SYSTEM_INSPECTOR][${reqId}] Audit Complete.`);
    return new Response(JSON.stringify(finalReport, null, 2), {
      headers: { 'Content-Type': 'application/json' }
    });

  } catch (err) {
    console.error(`[SYSTEM_INSPECTOR][${reqId}][ERROR]`, err);
    return new Response(JSON.stringify({ error: err.message }), { status: 500 });
  }
});

