2105 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2106 |     function applyLocalPatch(content, ops) {
2107 |         let lines = content.split('\n');
2108 |         let logs = [];
2109 |         let success = true;
2110 | 
2111 |         if (typeof ops === 'string') {
2112 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2113 |         }
2114 | 
2115 |         ops.forEach(op => {
2116 |             if (op.action === 'comment') return;
2117 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2118 |             
2119 |             if (op.action === 'replace_block') {
2120 |                 // Strategy 1: Exact String Match (Fastest)
2121 |                 const currentStr = lines.join('\n');
2122 |                 if (currentStr.includes(op.find_block)) {
2123 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2124 |                     logs.push('Exact match applied');
2125 |                     return;
2126 |                 }
2127 | 
2128 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2129 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2130 |                 if (searchLines.length === 0) return;
2131 | 
2132 |                 let matchStart = -1;
2133 |                 let matchEnd = -1;
2134 | 
2135 |                 // Scan file lines
2136 |                 for (let i = 0; i < lines.length; i++) {
2137 |                     // If first line matches (ignoring whitespace)
2138 |                     if (lines[i].trim() === searchLines[0]) {
2139 |                         // Check subsequent lines
2140 |                         let allMatch = true;
2141 |                         let fileOffset = 0;
2142 |                         let searchOffset = 1;
2143 |                         
2144 |                         while (searchOffset < searchLines.length) {
2145 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2146 |                             const nextFile = lines[i + fileOffset + 1].trim();
2147 |                             // Skip empty lines in file if they aren't in search block
2148 |                             if (nextFile === '') {
2149 |                                 fileOffset++;
2150 |                                 continue;
2151 |                             }
2152 |                             if (nextFile !== searchLines[searchOffset]) {
2153 |                                 allMatch = false;
2154 |                                 break;
2155 |                             }
2156 |                             fileOffset++;
2157 |                             searchOffset++;
2158 |                         }
2159 | 
2160 |                         if (allMatch) {
2161 |                             matchStart = i;
2162 |                             matchEnd = i + fileOffset;
2163 |                             break;
2164 |                         }
2165 |                     }
2166 |                 }
2167 | 
2168 |                 if (matchStart !== -1) {
2169 |                     // Replace the range of lines
2170 |                     const replacement = op.replace_with.split('\n');
2171 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2172 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2173 |                 } else {
2174 |                     success = false;
2175 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2176 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2177 |                 }
2178 |             }
2179 |         });
2180 |         return { content: lines.join('\n'), success, logs };
2181 |     }
