4568 |         return items.filter(item => {
4569 |             // 1. Time Filter
4570 |             if (f.time !== 'all') {
4571 |                 const ts = new Date(item.created_at).getTime();
4572 |                 const diff = now - ts;
4573 |                 if (f.time === 'hour' && diff > 3600000) return false;
4574 |                 if (f.time === 'today' && diff > 86400000) return false;
4575 |                 if (f.time === 'week' && diff > 604800000) return false;
4576 |             }
4577 | 
4578 |             // 2. File Filter
4579 |             if (f.files.length > 0) {
4580 |                 let touchedFiles = [];
4581 |                 if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path || '');
4582 |                 if (tab === 'patcher') {
4583 |                     // Patcher logic is handled by applyFiltersToPatcher, but we add safety here
4584 |                     touchedFiles = (item.results || []).map(r => r.file);
4585 |                 }
4586 |                 if (tab === 'cicd') {
4587 |                     const match = dbHistory.find(h => h.sha === item.head_commit.id);
4588 |                     touchedFiles = match ? (match.ops || []).map(o => o.file_path || '') : [];
4589 |                 }
4590 |                 // Filter out empty paths
4591 |                 touchedFiles = touchedFiles.filter(p => p !== '');
4592 |                 if (touchedFiles.length > 0 && !touchedFiles.some(tf => f.files.includes(tf))) return false;
4593 |             }
4594 |             return true;
4595 |         });
