4887 |     function formatBytes(bytes) {
4888 |         if (!bytes) return '0 B';
4889 |         const k = 1024;
4890 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4891 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4892 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4893 |     }
