4895 |     function timeAgo(dateString) {
4896 |         const date = new Date(dateString);
4897 |         const now = new Date();
4898 |         const seconds = Math.floor((now - date) / 1000);
4899 |         if (seconds < 10) return 'just now';
4900 |         if (seconds < 60) return seconds + 's ago';
4901 |         const minutes = Math.floor(seconds / 60);
4902 |         if (minutes < 60) return minutes + 'm ago';
4903 |         const hours = Math.floor(minutes / 60);
4904 |         if (hours < 24) return hours + 'h ago';
4905 |         return date.toLocaleDateString();
4906 |     }
