6247 |             diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
6248 |             diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
6249 |             diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
6250 |             diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
6251 |         }
6252 | 
6253 |         diffLeft.setValue("Loading...", -1);
6254 |         diffRight.setValue("Loading...", -1);
6255 | 
6256 |         try {
6257 |             let leftContent = "", rightContent = "";
6258 | 
6259 |             if (forcedLeft !== null && forcedRight !== null) {
6260 |                 leftContent = forcedLeft;
6261 |                 rightContent = forcedRight;
6262 |             } else {
6263 |                 const rightRef = data.commit_sha || 'HEAD';
6264 |                 const leftRef = rightRef + '^';
6265 | 
6266 |                 const fetchFile = async (ref) => {
6267 |                     const res = await fetch(CONFIG.funcUrl, {
6268 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
6269 |                         body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
6270 |                     });
6271 |                     const d = await res.json();
6272 |                     return d.content ? b64DecodeUnicode(d.content) : '';
6273 |                 };
6274 | 
6275 |                 const results = await Promise.all([
6276 |                     fetchFile(leftRef).catch(() => ""),
6277 |                     fetchFile(rightRef).catch(() => "")
6278 |                 ]);
6279 |                 leftContent = results[0];
6280 |                 rightContent = results[1];
6281 |             }
6282 | 
6283 |             let mode = "ace/mode/text";
6284 |             if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
6285 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
6286 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
6287 |             else if (data.file.endsWith('.json')) mode = "ace/mode/json";
6288 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
6289 |             
6290 |             diffLeft.session.setMode(mode);
6291 |             diffLeft.setValue(leftContent, -1);
6292 |             
6293 |             diffRight.session.setMode(mode);
6294 |             diffRight.setValue(rightContent, -1);
6295 | 
6296 |             const Range = ace.require('ace/range').Range;
6297 | 
6298 |             // Helper to get Range from String Index
6299 |             const getRangeFromText = (session, searchText) => {
6300 |                 const fullText = session.getValue();
6301 |                 // 1. Try Exact Match
6302 |                 let startIdx = fullText.indexOf(searchText);
6303 |                 
6304 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
6305 |                 if (startIdx === -1) {
6306 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
6307 |                     startIdx = clean(fullText).indexOf(clean(searchText));
6308 |                 }
6309 | 
6310 |                 if (startIdx !== -1) {
6311 |                     const linesBefore = fullText.substring(0, startIdx).split('\n');
6312 |                     const startRow = linesBefore.length - 1;
6313 |                     const startCol = linesBefore[startRow].length;
6314 |                     const linesInSearch = searchText.split('\n');
6315 |                     const endRow = startRow + linesInSearch.length - 1;
6316 |                     const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
6317 |                     return new Range(startRow, startCol, endRow, endCol);
6318 |                 }
6319 |                 return null;
6320 |             };
6321 |             
6322 |             const searchRemove = data.op.find_block || data.op.anchor;
6323 |             if(searchRemove) {
6324 |                 const range = getRangeFromText(diffLeft.session, String(searchRemove));
6325 |                 if(range) {
6326 |                     diffLeft.session.addMarker(range, "marker-remove", "fullLine");
6327 |                     diffLeft.scrollToLine(range.start.row, true, true, function() {});
6328 |                 }
6329 |             }
6330 | 
6331 |             const searchAdd = data.op.replace_with || data.op.content;
6332 |             if(searchAdd) {
