6456 |         checkboxes.forEach(cb => {
6457 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
6458 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
6459 |         });
