7271 |     function extractTableNames(sql) {
7272 |         if (!sql) return [];
7273 |         const tables = [];
7274 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7275 |         
7276 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7277 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7278 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7279 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7280 | 
7281 |         let match;
7282 |         while ((match = fromRegex.exec(sql)) !== null) {
7283 |             const name = match[1];
7284 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7285 |                 tables.push(name);
7286 |             }
7287 |         }
7288 |         
7289 |         while ((match = metaRegex.exec(sql)) !== null) {
7290 |             const name = match[1];
7291 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7292 |                 tables.push(name);
7293 |             }
7294 |         }
7295 | 
7296 |         return tables;
7297 |     }
