7299 |     function convertToCSV(resultObj) {
7300 |         const data = resultObj.data || [];
7301 |         if (!data.length) return '';
7302 |         
7303 |         const tables = extractTableNames(resultObj.sql);
7304 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7305 | 
7306 |         const headers = Object.keys(data[0]);
7307 |         const rows = data.map(row => 
7308 |             headers.map(header => {
7309 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7310 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7311 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7312 |             }).join(',')
7313 |         );
7314 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7315 |     }
